+NPY_FINLINE vec_f32
+simd_range_reduction_f32(vec_f32& x, vec_f32& y, const vec_f32& c1, const vec_f32& c2, const vec_f32& c3)
+{
+    vec_f32 reduced_x = hn::MulAdd(y, c1, x);
+    reduced_x = hn::MulAdd(y, c2, reduced_x);
+    reduced_x = hn::MulAdd(y, c3, reduced_x);
+    return reduced_x;
